package com.restaurantcraft.registry; import com.restaurantcraft.RestaurantCraft; import net.minecraft.core.registries.Registries; import net.minecraft.network.chat.Component; import net.minecraft.world.item.*; import net.minecraftforge.eventbus.api.IEventBus; import net.minecraftforge.registries.*; public class ModCreativeTabs { public static final DeferredRegister<CreativeModeTab> TABS=DeferredRegister.create(Registries.CREATIVE_MODE_TAB,RestaurantCraft.MODID); public static final RegistryObject<CreativeModeTab> RESTAURANT_CRAFT=TABS.register("restaurant_craft",()->CreativeModeTab.builder().title(Component.translatable("itemGroup.restaurant_craft")).icon(()->new ItemStack(ModItems.ALL.get(0).get())).displayItems((p,out)->ModItems.ALL.forEach(i->out.accept(i.get()))).build()); public static void register(IEventBus bus){TABS.register(bus);} }
